import{c as t,Q as a,j as r,m as o}from"./chunks/framework.BXc4yaFE.js";const d=JSON.parse(`{"title":"If You're Not Using These 100 Repos, Delete CLAUDE CODE — @0x_kaize","description":"","frontmatter":{"title":"If You're Not Using These 100 Repos, Delete CLAUDE CODE — @0x_kaize","author":"0x_kaize（@0x_kaize）","date":"2026-04-25T00:00:00.000Z","source":"https://x.com/0x_kaize/status/2048059417661174052","type":"tweet"},"headers":[],"relativePath":"research/tweets/2026-04-25-@0x_kaize-174052.md","filePath":"research/tweets/2026-04-25-@0x_kaize-174052.md","lastUpdated":1779894392000}`),s={name:"research/tweets/2026-04-25-@0x_kaize-174052.md"};function l(i,e,c,n,h,p){return a(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="if-you-re-not-using-these-100-repos-delete-claude-code-—-0x-kaize" tabindex="-1">If You&#39;re Not Using These 100 Repos, Delete CLAUDE CODE — @0x_kaize <a class="header-anchor" href="#if-you-re-not-using-these-100-repos-delete-claude-code-—-0x-kaize" aria-label="Permalink to &quot;If You&#39;re Not Using These 100 Repos, Delete CLAUDE CODE — @0x_kaize&quot;">​</a></h1><p><strong>來源</strong>：<a href="https://x.com/0x_kaize/status/2048059417661174052" target="_blank" rel="noreferrer">https://x.com/0x_kaize/status/2048059417661174052</a><strong>作者</strong>：0x_kaize（@0x_kaize） <strong>發布日期</strong>：2026-04-25 <strong>收錄日期</strong>：2026-04-26 <strong>類型</strong>：Twitter Article <strong>統計</strong>：316 likes · 28 retweets · 1,558 bookmarks · 238,449 views</p><hr><h2 id="全文" tabindex="-1">全文 <a class="header-anchor" href="#全文" aria-label="Permalink to &quot;全文&quot;">​</a></h2><p>Most people think of Claude Code as &quot;just another AI coding tool.&quot;</p><p>I thought the same - until I discovered configs, plugins, skills, and subagents.</p><p>Before that, I was writing the same prompts over and over. Losing context every session. Wondering why other devs were 5x more productive with the same tool.</p><p>So I decided to figure out how to work better. The answer: REPOSITORIES.</p><p>I put together a collection of the 100 best repositories:</p><h4 id="category-1-awesome-lists-meta-indexes" tabindex="-1">CATEGORY 1 - AWESOME LISTS &amp; META-INDEXES <a class="header-anchor" href="#category-1-awesome-lists-meta-indexes" aria-label="Permalink to &quot;CATEGORY 1 - AWESOME LISTS &amp; META-INDEXES&quot;">​</a></h4><p>The Claude Code ecosystem is evolving so rapidly that it&#39;s hard to keep up. New features appear every day, plugins come and go, and half of all the interesting stuff never even makes it to Hacker News.</p><p>Awesome lists help solve this problem. These are community-maintained directories that take on the work of searching: they classify, rank, and filter content based on actual quality, not the number of stars on GitHub.</p><p>1/ awesome-claude-code — <a href="https://github.com/hesreallyhim/awesome-claude-code" target="_blank" rel="noreferrer">https://github.com/hesreallyhim/awesome-claude-code</a> (28.5k+ stars, only Claude itself is allowed to submit PRs)</p><p>2/ awesome-claude-skills (ComposioHQ) — <a href="https://github.com/ComposioHQ/awesome-claude-skills" target="_blank" rel="noreferrer">https://github.com/ComposioHQ/awesome-claude-skills</a> (50+ production-ready skills, cross-compatible with Claude Code, Codex, Cursor, Gemini CLI)</p><p>3/ awesome-claude-plugins (ComposioHQ) — <a href="https://github.com/ComposioHQ/awesome-claude-plugins" target="_blank" rel="noreferrer">https://github.com/ComposioHQ/awesome-claude-plugins</a></p><p>4/ awesome-claude-prompts — <a href="https://github.com/langgptai/awesome-claude-prompts" target="_blank" rel="noreferrer">https://github.com/langgptai/awesome-claude-prompts</a> (4.2k+ stars, XML-structured prompts)</p><p>5/ awesome-claude — <a href="https://github.com/alvinunreal/awesome-claude" target="_blank" rel="noreferrer">https://github.com/alvinunreal/awesome-claude</a></p><p>6/ awesome-agent-skills (VoltAgent) — <a href="https://github.com/VoltAgent/awesome-agent-skills" target="_blank" rel="noreferrer">https://github.com/VoltAgent/awesome-agent-skills</a> (1000+ agent skills, battle-tested)</p><p>7/ awesome-claude-code-subagents (VoltAgent) — <a href="https://github.com/VoltAgent/awesome-claude-code-subagents" target="_blank" rel="noreferrer">https://github.com/VoltAgent/awesome-claude-code-subagents</a></p><p>8/ awesome-claude-code-plugins (ccplugins) — <a href="https://github.com/ccplugins/awesome-claude-code-plugins" target="_blank" rel="noreferrer">https://github.com/ccplugins/awesome-claude-code-plugins</a></p><p>9/ awesome-claude-code (jqueryscript) — <a href="https://github.com/jqueryscript/awesome-claude-code" target="_blank" rel="noreferrer">https://github.com/jqueryscript/awesome-claude-code</a></p><p>10/ Claude-Code-Repos-Index — <a href="https://github.com/danielrosehill/Claude-Code-Repos-Index" target="_blank" rel="noreferrer">https://github.com/danielrosehill/Claude-Code-Repos-Index</a> (75+ quality repos, by Daniel Rosehill)</p><h4 id="category-2-official-anthropic-repos" tabindex="-1">CATEGORY 2 - OFFICIAL ANTHROPIC REPOS <a class="header-anchor" href="#category-2-official-anthropic-repos" aria-label="Permalink to &quot;CATEGORY 2 - OFFICIAL ANTHROPIC REPOS&quot;">​</a></h4><p>Before you start working with any community repository, begin with these.</p><p>11/ anthropics/claude-code — <a href="https://github.com/anthropics/claude-code" target="_blank" rel="noreferrer">https://github.com/anthropics/claude-code</a> (55k+ stars, the official CLI)</p><p>12/ anthropics/skills — <a href="https://github.com/anthropics/skills" target="_blank" rel="noreferrer">https://github.com/anthropics/skills</a> (37.5k+ stars, official Agent Skills)</p><p>13/ anthropics/claude-plugins — <a href="https://github.com/anthropics/claude-plugins" target="_blank" rel="noreferrer">https://github.com/anthropics/claude-plugins</a> (2.8k+ stars)</p><p>14/ anthropics/claude-code-sdk-python — <a href="https://github.com/anthropics/claude-code-sdk-python" target="_blank" rel="noreferrer">https://github.com/anthropics/claude-code-sdk-python</a> (6.1k+ stars)</p><p>15/ anthropics/claude-agent-sdk-typescript — <a href="https://github.com/anthropics/claude-agent-sdk-typescript" target="_blank" rel="noreferrer">https://github.com/anthropics/claude-agent-sdk-typescript</a></p><p>16/ anthropics/claude-code-security-review — <a href="https://github.com/anthropics/claude-code-security-review" target="_blank" rel="noreferrer">https://github.com/anthropics/claude-code-security-review</a> (2.8k+ stars, AI-powered security review GitHub Action)</p><p>17/ anthropics/claude-code-action — <a href="https://github.com/anthropics/claude-code-action" target="_blank" rel="noreferrer">https://github.com/anthropics/claude-code-action</a> (Official GitHub Action)</p><p>18/ github/github-mcp-server — <a href="https://github.com/github/github-mcp-server" target="_blank" rel="noreferrer">https://github.com/github/github-mcp-server</a> (most-used MCP server)</p><p>19/ anthropic-cookbook — <a href="https://github.com/anthropics/anthropic-cookbook" target="_blank" rel="noreferrer">https://github.com/anthropics/anthropic-cookbook</a></p><p>20/ courses (Anthropic) — <a href="https://github.com/anthropics/courses" target="_blank" rel="noreferrer">https://github.com/anthropics/courses</a></p><h4 id="category-3-skills-collections" tabindex="-1">CATEGORY 3 - SKILLS COLLECTIONS <a class="header-anchor" href="#category-3-skills-collections" aria-label="Permalink to &quot;CATEGORY 3 - SKILLS COLLECTIONS&quot;">​</a></h4><p>Skills are Markdown files that teach Claude how to perform specific tasks. The beauty of it is that good skills let you transform Claude from a general-purpose assistant into an expert on demand.</p><p>21/ obra/superpowers — <a href="https://github.com/obra/superpowers" target="_blank" rel="noreferrer">https://github.com/obra/superpowers</a> (148k+ stars, brainstorm → spec → plan → TDD → review → merge)</p><p>22/ obra/superpowers-marketplace — <a href="https://github.com/obra/superpowers-marketplace" target="_blank" rel="noreferrer">https://github.com/obra/superpowers-marketplace</a> (20+ battle-tested skills)</p><p>23/ obra/superpowers-skills — <a href="https://github.com/obra/superpowers-skills" target="_blank" rel="noreferrer">https://github.com/obra/superpowers-skills</a></p><p>24/ obra/superpowers-lab — <a href="https://github.com/obra/superpowers-lab" target="_blank" rel="noreferrer">https://github.com/obra/superpowers-lab</a> (experimental)</p><p>25/ everything-claude-code — <a href="https://github.com/affaan-m/everything-claude-code" target="_blank" rel="noreferrer">https://github.com/affaan-m/everything-claude-code</a> (30 agents, 136 skills, 60 slash commands, 1282 tests, 98% coverage, Cerebral Valley x Anthropic hackathon winner)</p><p>26/ travisvn/awesome-claude-skills — <a href="https://github.com/travisvn/awesome-claude-skills" target="_blank" rel="noreferrer">https://github.com/travisvn/awesome-claude-skills</a> (22k+ installs)</p><p>27/ trailofbits/claude-code-skills — <a href="https://github.com/trailofbits/claude-code-skills" target="_blank" rel="noreferrer">https://github.com/trailofbits/claude-code-skills</a> (security research skills by Trail of Bits)</p><p>28/ K-Dense-AI/claude-scientific-skills — <a href="https://github.com/K-Dense-AI/claude-scientific-skills" target="_blank" rel="noreferrer">https://github.com/K-Dense-AI/claude-scientific-skills</a></p><p>29/ ay-automate/ay-skills — <a href="https://github.com/ay-automate/ay-skills" target="_blank" rel="noreferrer">https://github.com/ay-automate/ay-skills</a> (10 skills: SEO audits, Remotion video, diagrams)</p><p>30/ BehiSecc/awesome-claude-skills — <a href="https://github.com/BehiSecc/awesome-claude-skills" target="_blank" rel="noreferrer">https://github.com/BehiSecc/awesome-claude-skills</a></p><h4 id="category-4-agents-subagents" tabindex="-1">CATEGORY 4 - AGENTS &amp; SUBAGENTS <a class="header-anchor" href="#category-4-agents-subagents" aria-label="Permalink to &quot;CATEGORY 4 - AGENTS &amp; SUBAGENTS&quot;">​</a></h4><p>Subagents solve the context clutter problem: instead of a single Claude handling 20 tasks, you get a team of specialists.</p><p>31/ wshobson/agents — <a href="https://github.com/wshobson/agents" target="_blank" rel="noreferrer">https://github.com/wshobson/agents</a> (25k+ stars, strategy/dev/security/design/data/research)</p><p>32/ awesome-claude-agents — <a href="https://github.com/vijaythecoder/awesome-claude-agents" target="_blank" rel="noreferrer">https://github.com/vijaythecoder/awesome-claude-agents</a> (3.7k+ stars)</p><p>33/ davepoon/claude-code-subagents-collection — <a href="https://github.com/davepoon/claude-code-subagents-collection" target="_blank" rel="noreferrer">https://github.com/davepoon/claude-code-subagents-collection</a> (100+ production-ready, 2.2k+ stars)</p><p>34/ claude-code-agents (59 specialists) — <a href="https://github.com/baryhuang/claude-code-agents" target="_blank" rel="noreferrer">https://github.com/baryhuang/claude-code-agents</a></p><p>35/ multi-agent-squad — <a href="https://github.com/ruvnet/multi-agent-squad" target="_blank" rel="noreferrer">https://github.com/ruvnet/multi-agent-squad</a></p><p>36/ Agent-Fusion — <a href="https://github.com/0xAsten/Agent-Fusion" target="_blank" rel="noreferrer">https://github.com/0xAsten/Agent-Fusion</a> (multi-agent across Claude Code, Codex CLI, Amazon Q, Gemini)</p><p>37/ sub-agents — <a href="https://github.com/webdevtodayjason/sub-agents" target="_blank" rel="noreferrer">https://github.com/webdevtodayjason/sub-agents</a> (175+ stars)</p><p>38/ sub-agents-directory — <a href="https://github.com/dotneet/sub-agents-directory" target="_blank" rel="noreferrer">https://github.com/dotneet/sub-agents-directory</a> (100+ subagent prompts)</p><p>39/ claude-code-heavy — <a href="https://github.com/iamcatdev/claude-code-heavy" target="_blank" rel="noreferrer">https://github.com/iamcatdev/claude-code-heavy</a> (72+ stars, parallel research agents)</p><p>40/ ClaudeCodeAgents — <a href="https://github.com/webdevtodayjason/ClaudeCodeAgents" target="_blank" rel="noreferrer">https://github.com/webdevtodayjason/ClaudeCodeAgents</a> (455+ stars, QA-focused)</p><h4 id="category-5-mcp-servers" tabindex="-1">CATEGORY 5 - MCP SERVERS <a class="header-anchor" href="#category-5-mcp-servers" aria-label="Permalink to &quot;CATEGORY 5 - MCP SERVERS&quot;">​</a></h4><p>MCP servers act as bridges connecting Claude to the rest of your stack: GitHub PRs, Postgres, browser, Figma.</p><p>41/ claude-code-mcp — <a href="https://github.com/steipete/claude-code-mcp" target="_blank" rel="noreferrer">https://github.com/steipete/claude-code-mcp</a> (Run Claude Code itself as an MCP server, agent-in-agent pattern)</p><p>42/ zilliztech/claude-context — <a href="https://github.com/zilliztech/claude-context" target="_blank" rel="noreferrer">https://github.com/zilliztech/claude-context</a> (semantic code search)</p><p>43/ claude-context-mode — <a href="https://github.com/d-e-s-o/claude-context-mode" target="_blank" rel="noreferrer">https://github.com/d-e-s-o/claude-context-mode</a> (2.2k+ stars, 315 KB → 5.4 KB, 98% context reduction)</p><p>44/ Continuous-Claude-v2 — <a href="https://github.com/continuous-claude/continuous-claude-v2" target="_blank" rel="noreferrer">https://github.com/continuous-claude/continuous-claude-v2</a> (2.2k+ stars, ledger-based hooks)</p><p>45/ context7 — <a href="https://github.com/upstash/context7" target="_blank" rel="noreferrer">https://github.com/upstash/context7</a> (up-to-date version-specific docs)</p><p>46/ postgres-mcp — <a href="https://github.com/crystaldba/postgres-mcp" target="_blank" rel="noreferrer">https://github.com/crystaldba/postgres-mcp</a> (safe PostgreSQL, read-only default)</p><p>47/ playwright-mcp — <a href="https://github.com/microsoft/playwright-mcp" target="_blank" rel="noreferrer">https://github.com/microsoft/playwright-mcp</a> (browser automation, Microsoft-backed)</p><p>48/ mcp-server-sqlite — <a href="https://github.com/modelcontextprotocol/servers" target="_blank" rel="noreferrer">https://github.com/modelcontextprotocol/servers</a></p><p>49/ claude-code-mcp-enhanced — <a href="https://github.com/grahama1970/claude-code-mcp-enhanced" target="_blank" rel="noreferrer">https://github.com/grahama1970/claude-code-mcp-enhanced</a></p><p>50/ danielrosehill/Claude-Code-MCP-List — <a href="https://github.com/danielrosehill/Claude-Code-MCP-List" target="_blank" rel="noreferrer">https://github.com/danielrosehill/Claude-Code-MCP-List</a></p><h4 id="category-6-orchestration-workflows" tabindex="-1">CATEGORY 6 - ORCHESTRATION &amp; WORKFLOWS <a class="header-anchor" href="#category-6-orchestration-workflows" aria-label="Permalink to &quot;CATEGORY 6 - ORCHESTRATION &amp; WORKFLOWS&quot;">​</a></h4><p>51/ Claude-Flow — <a href="https://github.com/ruvnet/claude-flow" target="_blank" rel="noreferrer">https://github.com/ruvnet/claude-flow</a> (11.4k+ stars, enterprise-grade multi-agent orchestration)</p><p>52/ claude-squad — <a href="https://github.com/smtg-ai/claude-squad" target="_blank" rel="noreferrer">https://github.com/smtg-ai/claude-squad</a> (5.6k+ stars, terminal multiplexer for AI coding agents)</p><p>53/ claude_code_agent_farm — <a href="https://github.com/Dicklesworthstone/claude_code_agent_farm" target="_blank" rel="noreferrer">https://github.com/Dicklesworthstone/claude_code_agent_farm</a> (parallel sessions at scale)</p><p>54/ ccpm (Claude Code PM) — <a href="https://github.com/automazeio/ccpm" target="_blank" rel="noreferrer">https://github.com/automazeio/ccpm</a> (by Ran Aroussi)</p><p>55/ cc-sessions — <a href="https://github.com/cc-sessions/cc-sessions" target="_blank" rel="noreferrer">https://github.com/cc-sessions/cc-sessions</a> (1.5k+ stars, hooks/subagents/commands)</p><p>56/ claude-sessions — <a href="https://github.com/iannuttall/claude-sessions" target="_blank" rel="noreferrer">https://github.com/iannuttall/claude-sessions</a> (1.1k+ stars)</p><p>57/ claude-code-infrastructure-showcase — <a href="https://github.com/diet103/claude-code-infrastructure-showcase" target="_blank" rel="noreferrer">https://github.com/diet103/claude-code-infrastructure-showcase</a></p><p>58/ infinite-agentic-loop — <a href="https://github.com/disler/infinite-agentic-loop" target="_blank" rel="noreferrer">https://github.com/disler/infinite-agentic-loop</a> (492+ stars)</p><p>59/ agentsys — <a href="https://github.com/agentsys/agentsys" target="_blank" rel="noreferrer">https://github.com/agentsys/agentsys</a> (473+ stars, 14 plugins, 43 agents, 30 skills)</p><p>60/ Citadel — <a href="https://github.com/gabrieltonnellier/citadel" target="_blank" rel="noreferrer">https://github.com/gabrieltonnellier/citadel</a> (430+ stars)</p><h4 id="category-7-memory-context" tabindex="-1">CATEGORY 7 - MEMORY &amp; CONTEXT <a class="header-anchor" href="#category-7-memory-context" aria-label="Permalink to &quot;CATEGORY 7 - MEMORY &amp; CONTEXT&quot;">​</a></h4><p>Every session starts from scratch. Memory tools provide persistent state across sessions.</p><p>61/ thedotmack/claude-mem — <a href="https://github.com/thedotmack/claude-mem" target="_blank" rel="noreferrer">https://github.com/thedotmack/claude-mem</a> (long-term memory via compression)</p><p>62/ hanfang/claude-memory-skill — <a href="https://github.com/hanfang/claude-memory-skill" target="_blank" rel="noreferrer">https://github.com/hanfang/claude-memory-skill</a></p><p>63/ 0xfurai/claude-subconscious — <a href="https://github.com/0xfurai/claude-subconscious" target="_blank" rel="noreferrer">https://github.com/0xfurai/claude-subconscious</a> (2.4k+ stars, background agent whispering)</p><p>64/ claude-code-semantic-memory — <a href="https://github.com/dheerajoruganty/claude-code-semantic-memory" target="_blank" rel="noreferrer">https://github.com/dheerajoruganty/claude-code-semantic-memory</a> (vector-based recall)</p><p>65/ claude-user-memory — <a href="https://github.com/brennercruvinel/claude-user-memory" target="_blank" rel="noreferrer">https://github.com/brennercruvinel/claude-user-memory</a> (125+ stars, 12 specialist agents)</p><p>66/ Repomix — <a href="https://github.com/yamadashy/repomix" target="_blank" rel="noreferrer">https://github.com/yamadashy/repomix</a> (20.9k+ stars, pack codebase into AI-readable file)</p><p>67/ graphify — <a href="https://github.com/safishamsi/graphify" target="_blank" rel="noreferrer">https://github.com/safishamsi/graphify</a> (knowledge graph from codebases)</p><p>68/ context-prime — <a href="https://github.com/elizaOS/context-prime" target="_blank" rel="noreferrer">https://github.com/elizaOS/context-prime</a> (by elizaOS)</p><p>69/ claude-code-heavy-research — <a href="https://github.com/iamcatdev/claude-code-heavy" target="_blank" rel="noreferrer">https://github.com/iamcatdev/claude-code-heavy</a></p><p>70/ ledger — <a href="https://github.com/continuous-claude/continuous-claude-v2" target="_blank" rel="noreferrer">https://github.com/continuous-claude/continuous-claude-v2</a></p><h4 id="category-8-slash-commands-hooks" tabindex="-1">CATEGORY 8 - SLASH COMMANDS &amp; HOOKS <a class="header-anchor" href="#category-8-slash-commands-hooks" aria-label="Permalink to &quot;CATEGORY 8 - SLASH COMMANDS &amp; HOOKS&quot;">​</a></h4><p>71/ wshobson/commands — <a href="https://github.com/wshobson/commands" target="_blank" rel="noreferrer">https://github.com/wshobson/commands</a> (1.7k+ stars, 57 production-ready slash commands: 15 workflows + 42 tools)</p><p>72/ nizos/tdd-guard — <a href="https://github.com/nizos/tdd-guard" target="_blank" rel="noreferrer">https://github.com/nizos/tdd-guard</a> (1.7k+ stars, automated TDD enforcement)</p><p>73/ ccundo — <a href="https://github.com/RonitSachdev/ccundo" target="_blank" rel="noreferrer">https://github.com/RonitSachdev/ccundo</a> (1.3k+ stars, granular undo)</p><p>74/ claude-canvas — <a href="https://github.com/claude-canvas/claude-canvas" target="_blank" rel="noreferrer">https://github.com/claude-canvas/claude-canvas</a> (1.1k+ stars, TUI toolkit)</p><p>75/ ClaudoPro Directory — <a href="https://github.com/ClaudoPro/claudopro-directory" target="_blank" rel="noreferrer">https://github.com/ClaudoPro/claudopro-directory</a></p><p>76/ danielrosehill/Claude-Slash-Commands — <a href="https://github.com/danielrosehill/Claude-Slash-Commands" target="_blank" rel="noreferrer">https://github.com/danielrosehill/Claude-Slash-Commands</a></p><p>77/ command-fix-issue — <a href="https://github.com/claude-commands/command-fix-issue" target="_blank" rel="noreferrer">https://github.com/claude-commands/command-fix-issue</a> (TDD-based GitHub issue fixer)</p><p>78/ Design Review Workflow — <a href="https://github.com/patrick-ellis/design-review-workflow" target="_blank" rel="noreferrer">https://github.com/patrick-ellis/design-review-workflow</a></p><p>79/ tdd-implement — <a href="https://github.com/jerseycheese/tdd-implement" target="_blank" rel="noreferrer">https://github.com/jerseycheese/tdd-implement</a></p><p>80/ security-review — <a href="https://github.com/anthropics/claude-code-security-review" target="_blank" rel="noreferrer">https://github.com/anthropics/claude-code-security-review</a></p><h4 id="category-9-guides-learning" tabindex="-1">CATEGORY 9 - GUIDES &amp; LEARNING <a class="header-anchor" href="#category-9-guides-learning" aria-label="Permalink to &quot;CATEGORY 9 - GUIDES &amp; LEARNING&quot;">​</a></h4><p>81/ ThamJiaHe/claude-prompt-engineering-guide — <a href="https://github.com/ThamJiaHe/claude-prompt-engineering-guide" target="_blank" rel="noreferrer">https://github.com/ThamJiaHe/claude-prompt-engineering-guide</a> (covers Opus 4.6/Sonnet 4.6/Haiku 4.5, 220+ verified sources)</p><p>82/ nikiforovall/claude-code-handbook — <a href="https://github.com/nikiforovall/claude-code-handbook" target="_blank" rel="noreferrer">https://github.com/nikiforovall/claude-code-handbook</a></p><p>83/ FlorianBruniaux/claude-code-ultimate-guide — <a href="https://github.com/FlorianBruniaux/claude-code-ultimate-guide" target="_blank" rel="noreferrer">https://github.com/FlorianBruniaux/claude-code-ultimate-guide</a> (22,000+ lines, 225 production templates)</p><p>84/ Piebald-AI/claude-code-system-prompts — <a href="https://github.com/Piebald-AI/claude-code-system-prompts" target="_blank" rel="noreferrer">https://github.com/Piebald-AI/claude-code-system-prompts</a> (all Claude Code system prompts, updated within minutes of each release, CHANGELOG across 155+ versions)</p><p>85/ Encyclopedia of Agentic Coding Patterns — <a href="https://github.com/wolfmcnally/Encyclopedia-of-Agentic-Coding-Patterns" target="_blank" rel="noreferrer">https://github.com/wolfmcnally/Encyclopedia-of-Agentic-Coding-Patterns</a> (190+ patterns)</p><p>86/ RiyaParikh0112/claude-code-playbook — <a href="https://github.com/RiyaParikh0112/claude-code-playbook" target="_blank" rel="noreferrer">https://github.com/RiyaParikh0112/claude-code-playbook</a></p><p>87/ 40+ Claude Code Tips — <a href="https://github.com/iannuttall/claude-code-tips" target="_blank" rel="noreferrer">https://github.com/iannuttall/claude-code-tips</a></p><p>88/ awesome-claude-prompts topic — <a href="https://github.com/topics/awesome-claude-prompts" target="_blank" rel="noreferrer">https://github.com/topics/awesome-claude-prompts</a></p><p>89/ Context Priming by disler — <a href="https://github.com/disler/context-priming" target="_blank" rel="noreferrer">https://github.com/disler/context-priming</a></p><p>90/ My Experience With Claude Code (2 weeks) — <a href="https://github.com/shaharia-lab/my-claude-code-journey" target="_blank" rel="noreferrer">https://github.com/shaharia-lab/my-claude-code-journey</a></p><h4 id="category-10-ide-integrations-desktop" tabindex="-1">CATEGORY 10 - IDE INTEGRATIONS &amp; DESKTOP <a class="header-anchor" href="#category-10-ide-integrations-desktop" aria-label="Permalink to &quot;CATEGORY 10 - IDE INTEGRATIONS &amp; DESKTOP&quot;">​</a></h4><p>91/ coder/claudecode.nvim — <a href="https://github.com/coder/claudecode.nvim" target="_blank" rel="noreferrer">https://github.com/coder/claudecode.nvim</a> (first Neovim integration, pure Lua, zero deps)</p><p>92/ greggh/claude-code.nvim — <a href="https://github.com/greggh/claude-code.nvim" target="_blank" rel="noreferrer">https://github.com/greggh/claude-code.nvim</a></p><p>93/ manzaltu/claude-code-ide.el — <a href="https://github.com/manzaltu/claude-code-ide.el" target="_blank" rel="noreferrer">https://github.com/manzaltu/claude-code-ide.el</a> (Emacs, ediff-based suggestions)</p><p>94/ stevemolitor/claude-code.el — <a href="https://github.com/stevemolitor/claude-code.el" target="_blank" rel="noreferrer">https://github.com/stevemolitor/claude-code.el</a></p><p>95/ Haleclipse/Claudix — <a href="https://github.com/Haleclipse/Claudix" target="_blank" rel="noreferrer">https://github.com/Haleclipse/Claudix</a> (VSCode extension)</p><p>96/ Clawd on Desk — <a href="https://github.com/Ruller-Lulu/clawd-on-desk" target="_blank" rel="noreferrer">https://github.com/Ruller-Lulu/clawd-on-desk</a> (desktop pet reacting to Claude sessions)</p><p>97/ Claude Desktop Debian — <a href="https://github.com/aaddrick/claude-desktop-debian" target="_blank" rel="noreferrer">https://github.com/aaddrick/claude-desktop-debian</a> (unofficial Linux package)</p><p>98/ instructkr/claw-code — <a href="https://github.com/instructkr/claw-code" target="_blank" rel="noreferrer">https://github.com/instructkr/claw-code</a></p><h4 id="category-11-specialized-workflows" tabindex="-1">CATEGORY 11 - SPECIALIZED WORKFLOWS <a class="header-anchor" href="#category-11-specialized-workflows" aria-label="Permalink to &quot;CATEGORY 11 - SPECIALIZED WORKFLOWS&quot;">​</a></h4><p>99/ nextlevelbuilder/ui-ux-pro-max-skill — <a href="https://github.com/nextlevelbuilder/ui-ux-pro-max-skill" target="_blank" rel="noreferrer">https://github.com/nextlevelbuilder/ui-ux-pro-max-skill</a></p><p>100/ ClaudeWave — <a href="https://github.com/claudewave/claudewave" target="_blank" rel="noreferrer">https://github.com/claudewave/claudewave</a> (real-time directory of 3800+ Claude repos, updated every 12 hours)</p><hr><h2 id="研究摘要" tabindex="-1">研究摘要 <a class="header-anchor" href="#研究摘要" aria-label="Permalink to &quot;研究摘要&quot;">​</a></h2><p><strong>TL;DR</strong>：100 個 Claude Code 生態系 GitHub repo 精選，分 11 類（Awesome Lists、官方 repo、Skills、Agents、MCP、Orchestration、Memory、Slash Commands、Guides、IDE、特化工作流），附 GitHub 連結與星標數，是現有最完整的 Claude Code 生態系索引。</p><h3 id="核心論點" tabindex="-1">核心論點 <a class="header-anchor" href="#核心論點" aria-label="Permalink to &quot;核心論點&quot;">​</a></h3><ul><li>Claude Code 生態系比大多數使用者認知的龐大，configs/plugins/skills/subagents 是少數人才掌握的槓桿層</li><li>分層分類策略：從 Awesome Lists 作為探索入口 → 官方 repo 作為穩定底座 → 社群 Skills/Agents 擴展能力</li><li>Memory/Context 類別是解決「每 session 從零開始」問題的關鍵，Repomix（20.9k stars）是高度成熟的解決方案</li><li>規模指標：obra/superpowers 148k+ stars、anthropics/claude-code 55k+ stars、claudewave 追蹤 3800+ repos</li></ul><h3 id="關鍵數據-工具" tabindex="-1">關鍵數據 / 工具 <a class="header-anchor" href="#關鍵數據-工具" aria-label="Permalink to &quot;關鍵數據 / 工具&quot;">​</a></h3><ul><li>obra/superpowers：148k+ stars（最高星標的 Skills 庫）</li><li>anthropics/claude-code：55k+ stars（官方 CLI）</li><li>awesome-claude-code (hesreallyhim)：28.5k+ stars，only Claude can submit PRs</li><li>everything-claude-code：30 agents、136 skills、60 slash commands、1282 tests、98% coverage</li><li>Repomix：20.9k+ stars（codebase → AI-readable file）</li><li>claude-context-mode：315 KB → 5.4 KB（98% context reduction）</li><li>ClaudeWave：即時追蹤 3800+ repos，每 12 小時更新</li></ul><h3 id="批判性觀察" tabindex="-1">批判性觀察 <a class="header-anchor" href="#批判性觀察" aria-label="Permalink to &quot;批判性觀察&quot;">​</a></h3><ul><li>部分 repo 星標數可能誇大（作者未交代篩選標準，star count 容易被刷）</li><li>100 個 repo 的「精選」清單對一般使用者而言資訊量過載，缺乏優先順序建議（哪 5-10 個最重要）</li><li>作者提供 Telegram 頻道而非公開驗證，難以交叉確認所有描述的準確性</li></ul><hr><h2 id="評分" tabindex="-1">評分 <a class="header-anchor" href="#評分" aria-label="Permalink to &quot;評分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>說明</th></tr></thead><tbody><tr><td>A. Workspace 可行動性 (30%)</td><td>9/10</td><td>直接提供 GitHub URLs 和安裝指令，可立即從 obras/superpowers、wshobson/agents 等補強 cc-workspace</td></tr><tr><td>B. 創新性 (20%)</td><td>6/10</td><td>彙整工作有價值，但非原創觀點，本質是索引而非新洞見</td></tr><tr><td>C. 證據品質 (20%)</td><td>6/10</td><td>提供星標數等具體數字，但無獨立驗證，且部分數字可疑</td></tr><tr><td>D. 技術深度 (15%)</td><td>5/10</td><td>描述層次淺，每個 repo 只有 3-4 行，缺乏技術比較</td></tr><tr><td>E. 泛化性 (15%)</td><td>8/10</td><td>跨任務/跨 stack 的索引，普遍適用</td></tr><tr><td><strong>加權總分</strong></td><td><strong>7.05/10</strong></td><td>9×0.3 + 6×0.2 + 6×0.2 + 5×0.15 + 8×0.15</td></tr></tbody></table><p><strong>整合決策</strong>：Skill <strong>理由</strong>：100 個 repo 索引是高價值的 cc-workspace 擴充來源，適合整合為 <code>claude-ecosystem-index</code> SKILL，提供「何時查找哪個 repo」的分類導航</p>',140)])])}const g=t(s,[["render",l]]);export{d as __pageData,g as default};
